{
    // معرف العميل اللي هيتبعتله العرض (إجباري)
    "customer_id": 1,

    // عدد المجموعات أو الأفراد (اختياري)
    "group_size": 5,

    // معرف العملة اللي هيتعرض بيها السعر للعميل (إجباري)
    "currency_id": 2,

    // معرف لغة طباعة العرض (إجباري)
    "language_id": 1,

    // تاريخ ووقت بداية العرض (إجباري)
    "start_date": "2026-07-01 14:00",

    // تاريخ ووقت نهاية صلاحية العرض (إجباري، لازم يكون بعد تاريخ البداية)
    "end_date": "2026-07-03 12:00",

    // معرف الفندق (إجباري)
    "hotel_id": 1,

    // تحديد ما إذا كان هذا العرض موصى به للعميل (اختياري، الافتراضي false)
    "is_recommended": true,

    // ملاحظات إضافية على العرض تظهر للعميل (اختياري)
    "notes": "برجاء توفير غرف متجاورة إن أمكن",

    // حالة العرض (اختياري، الافتراضي draft)
    // الحالات المتاحة: draft, pending, approved, sent
    "status": "draft",

    // الغرف والأسعار المختارة داخل العرض (إجباري على الأقل عنصر واحد)
    "items": [
        {
            // معرف السعر من جدول الأسعار (اللي بيربط الغرفة بالإطلالة بالوجبات)
            "price_id": 1,
            
            // عدد الغرف المطلوبة من السعر ده (إجباري)
            "room_count": 2
        }
    ]
}

{
    // الحالات المتاحة: draft, pending, approved, sent
    "status": "pending",

    "is_recommended": true,

